@@ -0,0 +1,239 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://frankensqlite.local/schemas/sample_sqlite_db_files/beads_benchmark_artifact_manifest.v1.schema.json",
+  "title": "FrankenSQLite Beads Benchmark Artifact Manifest (v1)",
+  "type": "object",
+  "additionalProperties": false,
+  "required": [
+    "schema_version",
+    "campaign_id",
+    "campaign_manifest_path",
+    "row_id",
+    "fixture_id",
+    "workload",
+    "concurrency",
+    "mode",
+    "placement_profile_id",
+    "hardware_class_id",
+    "retry_policy_id",
+    "build_profile_id",
+    "seed_policy_id",
+    "artifact_bundle_dir",
+    "artifact_bundle_relpath",
+    "artifact_names",
+    "provenance"
+  ],
+  "properties": {
+    "schema_version": {
+      "type": "string",
+      "const": "fsqlite-e2e.beads_benchmark_artifact_manifest.v1"
+    },
+    "campaign_id": {
+      "$ref": "#/$defs/id"
+    },
+    "campaign_manifest_path": {
+      "$ref": "#/$defs/non_empty_string"
+    },
+    "row_id": {
+      "$ref": "#/$defs/id"
+    },
+    "fixture_id": {
+      "$ref": "#/$defs/id"
+    },
+    "workload": {
+      "$ref": "#/$defs/id"
+    },
+    "concurrency": {
+      "type": "integer",
+      "minimum": 1
+    },
+    "mode": {
+      "type": "string",
+      "enum": [
+        "sqlite_reference",
+        "fsqlite_mvcc",
+        "fsqlite_single_writer"
+      ]
+    },
+    "placement_profile_id": {
+      "$ref": "#/$defs/id"
+    },
+    "hardware_class_id": {
+      "$ref": "#/$defs/id"
+    },
+    "retry_policy_id": {
+      "$ref": "#/$defs/id"
+    },
+    "build_profile_id": {
+      "$ref": "#/$defs/id"
+    },
+    "seed_policy_id": {
+      "$ref": "#/$defs/id"
+    },
+    "artifact_bundle_dir": {
+      "$ref": "#/$defs/non_empty_string"
+    },
+    "artifact_bundle_relpath": {
+      "$ref": "#/$defs/non_empty_string"
+    },
+    "artifact_names": {
+      "$ref": "#/$defs/artifact_names"
+    },
+    "provenance": {
+      "$ref": "#/$defs/provenance"
+    }
+  },
+  "$defs": {
+    "id": {
+      "type": "string",
+      "pattern": "^[A-Za-z0-9][A-Za-z0-9._:-]*$"
+    },
+    "non_empty_string": {
+      "type": "string",
+      "minLength": 1
+    },
+    "sha256": {
+      "type": "string",
+      "pattern": "^[0-9a-f]{64}$"
+    },
+    "artifact_names": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "result_jsonl",
+        "summary_md",
+        "manifest_json",
+        "logs_dir",
+        "profiles_dir"
+      ],
+      "properties": {
+        "result_jsonl": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "summary_md": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "manifest_json": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "logs_dir": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "profiles_dir": {
+          "$ref": "#/$defs/non_empty_string"
+        }
+      }
+    },
+    "command": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "tool",
+        "command_line"
+      ],
+      "properties": {
+        "tool": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "command_line": {
+          "$ref": "#/$defs/non_empty_string"
+        }
+      }
+    },
+    "tool_version": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "tool",
+        "version"
+      ],
+      "properties": {
+        "tool": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "version": {
+          "$ref": "#/$defs/non_empty_string"
+        }
+      }
+    },
+    "placement_policy": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "placement_profile_id",
+        "hardware_class_id",
+        "availability",
+        "command_hint",
+        "required"
+      ],
+      "properties": {
+        "placement_profile_id": {
+          "$ref": "#/$defs/id"
+        },
+        "hardware_class_id": {
+          "$ref": "#/$defs/id"
+        },
+        "availability": {
+          "type": "string",
+          "enum": [
+            "universal",
+            "topology_aware"
+          ]
+        },
+        "command_hint": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "required": {
+          "type": "boolean"
+        }
+      }
+    },
+    "provenance": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "source_revision",
+        "beads_data_hash",
+        "kernel_release",
+        "placement_policy",
+        "commands",
+        "tool_versions",
+        "fallback_notes"
+      ],
+      "properties": {
+        "source_revision": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "beads_data_hash": {
+          "$ref": "#/$defs/sha256"
+        },
+        "kernel_release": {
+          "$ref": "#/$defs/non_empty_string"
+        },
+        "placement_policy": {
+          "$ref": "#/$defs/placement_policy"
+        },
+        "commands": {
+          "type": "array",
+          "minItems": 1,
+          "items": {
+            "$ref": "#/$defs/command"
+          }
+        },
+        "tool_versions": {
+          "type": "array",
+          "minItems": 1,
+          "items": {
+            "$ref": "#/$defs/tool_version"
+          }
+        },
+        "fallback_notes": {
+          "type": "array",
+          "items": {
+            "$ref": "#/$defs/non_empty_string"
+          }
+        }
+      }
+    }
+  }
+}
